<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Expense Tracker</title>
    <style>
        * {
            margin: 0;
            padding: 0;
            box-sizing: border-box;
        }

        body {
            font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
            background: #f5f5f5;
            padding: 20px;
        }

        .container {
            max-width: 800px;
            margin: 0 auto;
            background: white;
            border-radius: 8px;
            box-shadow: 0 2px 8px rgba(0, 0, 0, 0.1);
            padding: 20px;
        }

        h1 {
            margin-bottom: 20px;
            color: #333;
        }

        .form-section {
            margin-bottom: 30px;
            padding-bottom: 20px;
            border-bottom: 1px solid #eee;
        }

        .form-section h2 {
            font-size: 18px;
            margin-bottom: 15px;
        }

        .form-group {
            margin-bottom: 15px;
        }

        label {
            display: block;
            margin-bottom: 5px;
            font-weight: 500;
            color: #555;
        }

        input[type="number"],
        input[type="date"],
        input[type="text"],
        select {
            width: 100%;
            padding: 8px 12px;
            border: 1px solid #ddd;
            border-radius: 4px;
            font-size: 14px;
        }

        input[type="number"]:focus,
        input[type="date"]:focus,
        input[type="text"]:focus,
        select:focus {
            outline: none;
            border-color: #4CAF50;
            box-shadow: 0 0 0 2px rgba(76, 175, 80, 0.1);
        }

        button {
            padding: 10px 20px;
            background: #4CAF50;
            color: white;
            border: none;
            border-radius: 4px;
            cursor: pointer;
            font-size: 14px;
            font-weight: 500;
        }

        button:hover {
            background: #45a049;
        }

        #form-error {
            color: #d32f2f;
            margin-top: 10px;
            font-size: 14px;
            display: none;
        }

        #form-error.show {
            display: block;
        }

        .filters-section {
            margin-bottom: 30px;
            padding: 15px;
            background: #f9f9f9;
            border-radius: 4px;
        }

        .filters-section h3 {
            margin-bottom: 15px;
            color: #333;
            font-size: 16px;
        }

        .filter-group {
            display: grid;
            grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
            gap: 15px;
        }

        .summary-section {
            margin-bottom: 20px;
            padding: 15px;
            background: #e8f5e9;
            border-radius: 4px;
        }

        #total {
            font-size: 24px;
            font-weight: bold;
            color: #2e7d32;
        }

        .cat-totals {
            display: grid;
            grid-template-columns: repeat(auto-fit, minmax(150px, 1fr));
            gap: 10px;
            margin-top: 15px;
        }

        .cat-total {
            padding: 10px;
            background: white;
            border-radius: 4px;
            border-left: 4px solid #4CAF50;
        }

        .cat-total-label {
            font-size: 12px;
            color: #666;
            text-transform: capitalize;
        }

        .cat-total-value {
            font-size: 18px;
            font-weight: bold;
            color: #2e7d32;
        }

        .expenses-section {
            margin-top: 30px;
        }

        .expenses-section h2 {
            margin-bottom: 15px;
            color: #333;
        }

        .expenses-list {
            display: flex;
            flex-direction: column;
            gap: 10px;
        }

        .expense {
            display: grid;
            grid-template-columns: 80px 1fr 80px;
            gap: 15px;
            align-items: center;
            padding: 15px;
            background: #fafafa;
            border-radius: 4px;
            border-left: 4px solid #4CAF50;
        }

        .expense-amount {
            font-weight: bold;
            color: #2e7d32;
            font-size: 16px;
        }

        .expense-details {
            display: flex;
            flex-direction: column;
            gap: 5px;
        }

        .expense-category {
            text-transform: capitalize;
            font-weight: 500;
            color: #333;
        }

        .expense-date {
            font-size: 13px;
            color: #666;
        }

        .expense-note {
            font-size: 12px;
            color: #999;
            font-style: italic;
        }

        .exp-del {
            padding: 6px 12px;
            background: #d32f2f;
            font-size: 12px;
            width: fit-content;
        }

        .exp-del:hover {
            background: #b71c1c;
        }

        .empty-state {
            text-align: center;
            padding: 40px 20px;
            color: #999;
            display: none;
        }
    </style>
</head>
<body>
    <div class="container">
        <h1>Expense Tracker</h1>

        <div class="form-section">
            <h2>Add Expense</h2>
            <form id="expense-form">
                <div class="form-group">
                    <label for="amount">Amount</label>
                    <input type="number" id="amount" placeholder="0.00" step="0.01">
                </div>
                <div class="form-group">
                    <label for="category">Category</label>
                    <select id="category">
                        <option value="">Select a category</option>
                        <option value="groceries">Groceries</option>
                        <option value="transport">Transport</option>
                        <option value="bills">Bills</option>
                        <option value="fun">Fun</option>
                    </select>
                </div>
                <div class="form-group">
                    <label for="date">Date</label>
                    <input type="date" id="date">
                </div>
                <div class="form-group">
                    <label for="note">Note (optional)</label>
                    <input type="text" id="note" placeholder="Add a note...">
                </div>
                <button type="submit" id="add-expense">Add Expense</button>
                <div id="form-error"></div>
            </form>
        </div>

        <div class="filters-section">
            <h3>Filters</h3>
            <div class="filter-group">
                <div class="form-group">
                    <label for="filter-category">Category</label>
                    <select id="filter-category">
                        <option value="">All Categories</option>
                        <option value="groceries">Groceries</option>
                        <option value="transport">Transport</option>
                        <option value="bills">Bills</option>
                        <option value="fun">Fun</option>
                    </select>
                </div>
                <div class="form-group">
                    <label for="filter-from">From</label>
                    <input type="date" id="filter-from">
                </div>
                <div class="form-group">
                    <label for="filter-to">To</label>
                    <input type="date" id="filter-to">
                </div>
            </div>
        </div>

        <div class="summary-section">
            <div>Total: $<span id="total">0.00</span></div>
            <div class="cat-totals" id="cat-totals"></div>
        </div>

        <div class="expenses-section">
            <h2>Expenses</h2>
            <div class="expenses-list" id="expenses-list"></div>
            <div class="empty-state" id="empty-state">No expenses to display</div>
        </div>
    </div>

    <script>
        const CATEGORIES = ['groceries', 'transport', 'bills', 'fun'];
        const STORAGE_KEY = 'expenses';
        let expenses = [];

        function init() {
            loadExpenses();
            render();
            attachEventListeners();
        }

        function loadExpenses() {
            const stored = localStorage.getItem(STORAGE_KEY);
            expenses = stored ? JSON.parse(stored) : [];
        }

        function saveExpenses() {
            localStorage.setItem(STORAGE_KEY, JSON.stringify(expenses));
        }

        function attachEventListeners() {
            document.getElementById('expense-form').addEventListener('submit', handleAddExpense);
            document.getElementById('filter-category').addEventListener('change', render);
            document.getElementById('filter-from').addEventListener('change', render);
            document.getElementById('filter-to').addEventListener('change', render);
        }

        function handleAddExpense(e) {
            e.preventDefault();

            const amountInput = document.getElementById('amount');
            const categoryInput = document.getElementById('category');
            const dateInput = document.getElementById('date');
            const noteInput = document.getElementById('note');
            const errorElement = document.getElementById('form-error');

            const amount = amountInput.value.trim();
            const category = categoryInput.value;
            const date = dateInput.value;

            errorElement.classList.remove('show');
            errorElement.textContent = '';

            if (!amount || isNaN(amount) || parseFloat(amount) <= 0) {
                errorElement.textContent = 'Please enter a valid amount greater than 0.';
                errorElement.classList.add('show');
                return;
            }

            if (!date) {
                errorElement.textContent = 'Please select a date.';
                errorElement.classList.add('show');
                return;
            }

            const expense = {
                id: Date.now(),
                amount: parseFloat(amount),
                category,
                date,
                note: noteInput.value.trim()
            };

            expenses.unshift(expense);
            saveExpenses();

            amountInput.value = '';
            categoryInput.value = '';
            dateInput.value = '';
            noteInput.value = '';

            render();
        }

        function getFilteredExpenses() {
            const categoryFilter = document.getElementById('filter-category').value;
            const dateFrom = document.getElementById('filter-from').value;
            const dateTo = document.getElementById('filter-to').value;

            return expenses.filter(exp => {
                if (categoryFilter && exp.category !== categoryFilter) return false;
                if (dateFrom && exp.date < dateFrom) return false;
                if (dateTo && exp.date > dateTo) return false;
                return true;
            });
        }

        function render() {
            renderExpenses();
            updateTotals();
        }

        function renderExpenses() {
            const list = document.getElementById('expenses-list');
            const emptyState = document.getElementById('empty-state');
            const filtered = getFilteredExpenses();

            list.innerHTML = '';

            if (filtered.length === 0) {
                emptyState.style.display = 'block';
                return;
            }

            emptyState.style.display = 'none';

            filtered.forEach(expense => {
                const row = document.createElement('div');
                row.className = 'expense';

                const amountDiv = document.createElement('div');
                amountDiv.className = 'expense-amount';
                amountDiv.textContent = '$' + expense.amount.toFixed(2);

                const detailsDiv = document.createElement('div');
                detailsDiv.className = 'expense-details';

                const categorySpan = document.createElement('div');
                categorySpan.className = 'expense-category';
                categorySpan.textContent = expense.category;

                const dateSpan = document.createElement('div');
                dateSpan.className = 'expense-date';
                dateSpan.textContent = new Date(expense.date).toLocaleDateString();

                detailsDiv.appendChild(categorySpan);
                detailsDiv.appendChild(dateSpan);

                if (expense.note) {
                    const noteSpan = document.createElement('div');
                    noteSpan.className = 'expense-note';
                    noteSpan.textContent = expense.note;
                    detailsDiv.appendChild(noteSpan);
                }

                const deleteBtn = document.createElement('button');
                deleteBtn.className = 'exp-del';
                deleteBtn.textContent = 'Delete';
                deleteBtn.addEventListener('click', () => deleteExpense(expense.id));

                row.appendChild(amountDiv);
                row.appendChild(detailsDiv);
                row.appendChild(deleteBtn);

                list.appendChild(row);
            });
        }

        function deleteExpense(id) {
            expenses = expenses.filter(exp => exp.id !== id);
            saveExpenses();
            render();
        }

        function updateTotals() {
            const filtered = getFilteredExpenses();
            const total = filtered.reduce((sum, exp) => sum + exp.amount, 0);
            document.getElementById('total').textContent = total.toFixed(2);

            const catTotalsDiv = document.getElementById('cat-totals');
            catTotalsDiv.innerHTML = '';

            const catTotals = {};
            CATEGORIES.forEach(cat => {
                catTotals[cat] = filtered
                    .filter(exp => exp.category === cat)
                    .reduce((sum, exp) => sum + exp.amount, 0);
            });

            CATEGORIES.forEach(cat => {
                const el = document.createElement('div');
                el.className = 'cat-total';
                el.setAttribute('data-cat', cat);
                el.innerHTML = `
                    <div class="cat-total-label">${cat}</div>
                    <div class="cat-total-value">$${catTotals[cat].toFixed(2)}</div>
                `;
                catTotalsDiv.appendChild(el);
            });
        }

        init();
    </script>
</body>
</html>
